import{_ as e,o as r,c as d,a4 as o}from"./chunks/framework.DiadTcoQ.js";const h=JSON.parse('{"title":"Verbes irréguliers courants","description":"","frontmatter":{},"headers":[],"relativePath":"module-3/irregular-verbs.md","filePath":"module-3/irregular-verbs.md"}'),a={name:"module-3/irregular-verbs.md"};function s(i,t,n,l,u,b){return r(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="verbes-irreguliers-courants" tabindex="-1">Verbes irréguliers courants <a class="header-anchor" href="#verbes-irreguliers-courants" aria-label="Permalink to “Verbes irréguliers courants”">​</a></h1><p>Les verbes irréguliers ne suivent pas les terminaisons standard. Ils sont incontournables — il faut les mémoriser.</p><h2 id="ir-aller" tabindex="-1">ir (aller) <a class="header-anchor" href="#ir-aller" aria-label="Permalink to “ir (aller)”">​</a></h2><table tabindex="0"><thead><tr><th>Pronom</th><th>Forme</th></tr></thead><tbody><tr><td>yo</td><td>voy</td></tr><tr><td>tú</td><td>vas</td></tr><tr><td>él / ella / usted</td><td>va</td></tr><tr><td>nosotros</td><td>vamos</td></tr><tr><td>vosotros</td><td>vais</td></tr><tr><td>ellos / ustedes</td><td>van</td></tr></tbody></table><blockquote><p><em>Voy al mercado.</em> — Je vais au marché. <em>¿Adónde vas?</em> — Tu vas où ?</p></blockquote><h2 id="tener-avoir-tenir" tabindex="-1">tener (avoir / tenir) <a class="header-anchor" href="#tener-avoir-tenir" aria-label="Permalink to “tener (avoir / tenir)”">​</a></h2><table tabindex="0"><thead><tr><th>Pronom</th><th>Forme</th></tr></thead><tbody><tr><td>yo</td><td>tengo</td></tr><tr><td>tú</td><td>tienes</td></tr><tr><td>él / ella / usted</td><td>tiene</td></tr><tr><td>nosotros</td><td>tenemos</td></tr><tr><td>vosotros</td><td>tenéis</td></tr><tr><td>ellos / ustedes</td><td>tienen</td></tr></tbody></table><blockquote><p><em>Tengo hambre.</em> — J&#39;ai faim. <em>¿Tienes hermanos?</em> — Tu as des frères et sœurs ?</p></blockquote><h2 id="querer-vouloir-aimer" tabindex="-1">querer (vouloir / aimer) <a class="header-anchor" href="#querer-vouloir-aimer" aria-label="Permalink to “querer (vouloir / aimer)”">​</a></h2><table tabindex="0"><thead><tr><th>Pronom</th><th>Forme</th></tr></thead><tbody><tr><td>yo</td><td>quiero</td></tr><tr><td>tú</td><td>quieres</td></tr><tr><td>él / ella / usted</td><td>quiere</td></tr><tr><td>nosotros</td><td>queremos</td></tr><tr><td>vosotros</td><td>queréis</td></tr><tr><td>ellos / ustedes</td><td>quieren</td></tr></tbody></table><blockquote><p><em>Quiero un café.</em> — Je veux un café. <em>Te quiero.</em> — Je t&#39;aime.</p></blockquote><h2 id="poder-pouvoir" tabindex="-1">poder (pouvoir) <a class="header-anchor" href="#poder-pouvoir" aria-label="Permalink to “poder (pouvoir)”">​</a></h2><table tabindex="0"><thead><tr><th>Pronom</th><th>Forme</th></tr></thead><tbody><tr><td>yo</td><td>puedo</td></tr><tr><td>tú</td><td>puedes</td></tr><tr><td>él / ella / usted</td><td>puede</td></tr><tr><td>nosotros</td><td>podemos</td></tr><tr><td>vosotros</td><td>podéis</td></tr><tr><td>ellos / ustedes</td><td>pueden</td></tr></tbody></table><blockquote><p><em>¿Puedes ayudarme?</em> — Tu peux m&#39;aider ? <em>No puedo venir.</em> — Je ne peux pas venir.</p></blockquote><h2 id="saber-savoir" tabindex="-1">saber (savoir) <a class="header-anchor" href="#saber-savoir" aria-label="Permalink to “saber (savoir)”">​</a></h2><table tabindex="0"><thead><tr><th>Pronom</th><th>Forme</th></tr></thead><tbody><tr><td>yo</td><td>sé</td></tr><tr><td>tú</td><td>sabes</td></tr><tr><td>él / ella / usted</td><td>sabe</td></tr><tr><td>nosotros</td><td>sabemos</td></tr><tr><td>vosotros</td><td>sabéis</td></tr><tr><td>ellos / ustedes</td><td>saben</td></tr></tbody></table><blockquote><p><em>No sé.</em> — Je ne sais pas. <em>¿Sabes cocinar?</em> — Tu sais cuisiner ?</p></blockquote><h2 id="venir-venir" tabindex="-1">venir (venir) <a class="header-anchor" href="#venir-venir" aria-label="Permalink to “venir (venir)”">​</a></h2><table tabindex="0"><thead><tr><th>Pronom</th><th>Forme</th></tr></thead><tbody><tr><td>yo</td><td>vengo</td></tr><tr><td>tú</td><td>vienes</td></tr><tr><td>él / ella / usted</td><td>viene</td></tr><tr><td>nosotros</td><td>venimos</td></tr><tr><td>vosotros</td><td>venís</td></tr><tr><td>ellos / ustedes</td><td>vienen</td></tr></tbody></table><blockquote><p><em>Vengo de París.</em> — Je viens de Paris. <em>¿Vienes con nosotros?</em> — Tu viens avec nous ?</p></blockquote><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p><strong>saber</strong> vs <strong>conocer</strong> — deux verbes pour &quot;savoir/connaître&quot; :</p><ul><li><strong>saber</strong> = savoir faire quelque chose, connaître un fait</li><li><strong>conocer</strong> = connaître une personne, un lieu</li></ul><p><em>Sé hablar español.</em> — Je sais parler espagnol. <em>Conozco Madrid.</em> — Je connais Madrid.</p></div>',21)])])}const c=e(a,[["render",s]]);export{h as __pageData,c as default};
